import requests

def check_garage_membership(garage_name):
    API_ENDPOINT = "https://api.goodgaragescheme.co.uk/check_membership"
    API_KEY = "your_api_key_here"
    headers = {"Authorization": f"Bearer {API_KEY}"}
    params = {"garage_name": garage_name}

    response = requests.get(API_ENDPOINT, headers=headers, params=params)

    if response.status_code == 200:
        data = response.json()
        return data.get("is_member", False), data.get("garage_details", {})
    else:
        raise Exception(f"Failed to check membership: {response.text}")

# Example usage:
is_member, details = check_garage_membership("ABC Auto Repairs")
print(f"Is member: {is_member}")
print(f"Garage details: {details}")
